            ContentJson = """{"title":"Purchase Orders Field Reference","groups":[{"heading":"PO Header Fields (New PO)","items":[{"label":"Vendor (required)","value":"Pick who you're ordering from. The list comes from your Vendors. You must choose a vendor before saving."},{"label":"Job (optional)","value":"Tie the order to a specific job so its material cost is tracked there. Shows as a link you can click in the order detail."},{"label":"Notes (optional)","value":"A place for free-form notes about the order — special instructions, shipping preferences, or internal comments."}]},{"heading":"Line Item Fields (New PO)","items":[{"label":"Part (required)","value":"Search your Parts Catalog and pick a part. Assemblies aren't shown — only parts you can buy."},{"label":"Ordered Quantity (required)","value":"How many units to order. Must be at least 1. Starts at 1 on a new line."},{"label":"Unit Price (required)","value":"Cost per unit. Fills in from the part's set price when available; you can change it. Must be 0 or more."},{"label":"Line Total","value":"Ordered Quantity times Unit Price, shown for each line. Filled in for you."},{"label":"Add Line button","value":"Adds the current part, quantity, and price as a new line, then clears the fields for the next one. You need at least one line to save."},{"label":"Remove Line (trash icon)","value":"Takes a line off the order before you save."},{"label":"PO Total","value":"Adds up all the line totals. Shown at the bottom of the line items."}]},{"heading":"PO Detail Fields (Read-Only)","items":[{"label":"PO Number","value":"A unique number created for you (for example, PO-00042). Shown at the top of the order."},{"label":"Status","value":"A colored label showing where the order stands. See the PO Statuses section below."},{"label":"Vendor","value":"The vendor's name, as a link. Click it to open the vendor's record."},{"label":"Job","value":"The linked job, if any, as a link. Click it to open the job."},{"label":"Expected Delivery Date","value":"When the materials are expected to arrive. Shown as MM/dd/yyyy."},{"label":"Submitted Date","value":"When the order was sent to the vendor. Blank until you send it."},{"label":"Acknowledged Date","value":"When the vendor confirmed the order. Blank until they confirm."},{"label":"Received Date","value":"When everything on the order arrived. Blank until it's fully received."},{"label":"Created / Updated","value":"When the order was created and last changed."}]},{"heading":"Line Item Detail Fields","items":[{"label":"Part Number","value":"The part's number, as a link. Click it to open the part."},{"label":"Description","value":"The part's description, from the catalog."},{"label":"Ordered Quantity","value":"How many units were ordered on this line."},{"label":"Received Quantity","value":"How many units have arrived so far. Updated when you receive items."},{"label":"Remaining Quantity","value":"Ordered minus Received, worked out for you. Zero means the line is fully received."},{"label":"Unit Price","value":"Cost per unit on this line."},{"label":"Line Total","value":"Ordered Quantity times Unit Price."},{"label":"Notes","value":"Optional notes for this line."}]},{"heading":"PO Statuses","items":[{"label":"Draft (gray)","value":"You're still preparing the order. You can add or remove lines, edit, delete, or cancel it. Not sent to the vendor yet."},{"label":"Submitted (blue)","value":"The order has been sent to the vendor. You're waiting for them to confirm. You can still cancel."},{"label":"Acknowledged (teal)","value":"The vendor confirmed the order. You can now receive items. You can still cancel."},{"label":"Partially Received (orange)","value":"Some items have arrived, but not all. You can keep receiving. You can no longer cancel."},{"label":"Received (green)","value":"Everything has arrived. You can close the order. Nothing left to receive."},{"label":"Closed (gray)","value":"The order was closed after receiving finished. No further actions."},{"label":"Cancelled (red)","value":"The order was cancelled. Only Draft, Submitted, and Acknowledged orders can be cancelled, and it asks you to confirm."}]},{"heading":"Receiving Fields (Receive Items)","items":[{"label":"Receivable Lines","value":"Lists only the lines that still have items to come. Fully received lines aren't shown."},{"label":"Quantity to Receive (per line)","value":"Enter how many units arrived for each line. Can't be more than what's still outstanding."},{"label":"Receive All button","value":"Fills in the outstanding amount for every line at once — handy when the whole shipment arrives together."},{"label":"Save","value":"Records what arrived and updates each line. May move the order to Partially Received or Received."}]},{"heading":"Blanket PO Fields","items":[{"label":"Is Blanket","value":"An on/off switch marking this as a long-term (blanket) order instead of a one-time one."},{"label":"Blanket Total Quantity","value":"The total quantity you've committed to under the agreement."},{"label":"Agreed Unit Price","value":"The price per unit you negotiated for the agreement."},{"label":"Blanket Expiration Date","value":"When the agreement runs out."},{"label":"Released Quantity","value":"The total of everything you've called off against the agreement so far."},{"label":"Remaining Quantity","value":"Total committed minus what you've called off, worked out for you."}]},{"heading":"Blanket Release Fields","items":[{"label":"Line Item (required)","value":"Choose which line on the order this release draws from."},{"label":"Quantity (required)","value":"How many units to call off in this release. At least 0.01."},{"label":"Requested Delivery Date (required)","value":"When you need this release delivered."},{"label":"Notes (optional)","value":"Free-form notes for this release."},{"label":"Release Status","value":"Open (blue), Sent (teal), Partial Received (orange), Received (green), or Cancelled (red)."}]},{"heading":"List Columns","items":[{"label":"PO Number","value":"The order's number. Click the heading to sort."},{"label":"Vendor","value":"The vendor's company name. Sortable."},{"label":"Job","value":"The linked job number, if any. Sortable."},{"label":"Status","value":"A colored label for the order's stage. Sortable, and you can filter by it."},{"label":"Lines","value":"How many lines are on the order. Sortable."},{"label":"Ordered","value":"Total units ordered across all lines. Sortable."},{"label":"Received","value":"Total units received across all lines. Sortable."},{"label":"Expected","value":"The expected delivery date. Sortable."},{"label":"Created","value":"When the order was created. Sortable."}]},{"heading":"Buttons and Actions","items":[{"label":"New Purchase Order","value":"Opens the form to create a new order."},{"label":"Save (new PO)","value":"Creates the order with all its lines. Stays off until the form is filled in correctly and has at least one line."},{"label":"Cancel (new PO)","value":"Closes the form without saving."},{"label":"Submit PO","value":"Sends the order to the vendor and moves it from Draft to Submitted. Shows only while it's a Draft."},{"label":"Acknowledge PO","value":"Records that the vendor confirmed, moving the order from Submitted to Acknowledged. Shows only while it's Submitted."},{"label":"Receive Items","value":"Opens the receiving form. Shows when the order is Acknowledged or Partially Received."},{"label":"Close PO","value":"Closes an order that's fully received. Shows only when the order is Received."},{"label":"Cancel PO","value":"Cancels the order after you confirm. Shows while it's Draft, Submitted, or Acknowledged."},{"label":"Delete PO","value":"Permanently removes a draft order after you confirm. Shows only while it's a Draft."},{"label":"Row click (list)","value":"Opens the order, showing its header, lines with quantities, receiving history, and available actions."},{"label":"Create Release (blanket POs)","value":"Opens a form to call off a new release against 